export function init(dropZoneElement, dotNetHelper) {
    function onDragOver(e) {
        e.preventDefault();
        e.stopPropagation();
        dropZoneElement.classList.add("drag-over");
    }

    function onDragLeave(e) {
        e.preventDefault();
        e.stopPropagation();
        dropZoneElement.classList.remove("drag-over");
    }

    function onDrop(e) {
        e.preventDefault();
        e.stopPropagation();
        dropZoneElement.classList.remove("drag-over");

        const files = Array.from(e.dataTransfer.files).map(f => ({
            name: f.name,
            size: f.size,
            type: f.type || "application/octet-stream"
        }));

        if (files.length > 0) {
            dotNetHelper.invokeMethodAsync("OnFilesDropped", files);
        }
    }

    dropZoneElement.addEventListener("dragover", onDragOver);
    dropZoneElement.addEventListener("dragleave", onDragLeave);
    dropZoneElement.addEventListener("drop", onDrop);

    return {
        dispose: () => {
            dropZoneElement.removeEventListener("dragover", onDragOver);
            dropZoneElement.removeEventListener("dragleave", onDragLeave);
            dropZoneElement.removeEventListener("drop", onDrop);
        }
    };
}

@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_dropZoneRef" class="file-drop-zone">
    <p>Drag &amp; drop files here</p>
</div>

@if (_droppedFiles.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _droppedFiles)
        {
            <li class="file-entry @(entry.IsOversize ? "file-error" : "")">
                @if (entry.IsOversize)
                {
                    <span class="file-info">
                        <strong>@entry.Info.Name</strong> &mdash; @FormatSize(entry.Info.Size) (@entry.Info.Type)
                    </span>
                    <span class="error-message">File exceeds 10 MB limit</span>
                }
                else
                {
                    <span class="file-info">
                        <strong>@entry.Info.Name</strong> &mdash; @FormatSize(entry.Info.Size) (@entry.Info.Type)
                    </span>
                }
                <button class="btn-remove" @onclick="() => RemoveFile(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    private const long MaxFileSize = 10L * 1024 * 1024; // 10 MB

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private ElementReference _dropZoneRef;
    private IJSObjectReference? _module;
    private IJSObjectReference? _dropZoneInstance;
    private DotNetObjectReference<FileDropZone>? _dotNetRef;

    private readonly List<DroppedFile> _droppedFiles = new();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>("import", "./js/fileDropZone.js");
            _dotNetRef = DotNetObjectReference.Create(this);
            _dropZoneInstance = await _module.InvokeAsync<IJSObjectReference>("init", _dropZoneRef, _dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnFilesDropped(List<FileInfo> files)
    {
        foreach (var file in files)
        {
            _droppedFiles.Add(new DroppedFile(file, file.Size > MaxFileSize));
        }

        await NotifyParent();
        StateHasChanged();
    }

    private async Task RemoveFile(DroppedFile entry)
    {
        _droppedFiles.Remove(entry);
        await NotifyParent();
    }

    private Task NotifyParent()
    {
        var accepted = _droppedFiles
            .Where(f => !f.IsOversize)
            .Select(f => f.Info)
            .ToList();
        return OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    public async ValueTask DisposeAsync()
    {
        if (_dropZoneInstance is not null)
        {
            await _dropZoneInstance.InvokeVoidAsync("dispose");
            await _dropZoneInstance.DisposeAsync();
        }
        if (_module is not null)
        {
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }

    private sealed record DroppedFile(FileInfo Info, bool IsOversize);
}

.file-drop-zone {
    border: 2px dashed #6c757d;
    border-radius: 8px;
    padding: 40px;
    text-align: center;
    color: #6c757d;
    background-color: #f8f9fa;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
}

::deep .drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
    color: #0d6efd;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 16px;
}

.file-entry {
    display: flex;
    align-items: center;
    flex-wrap: wrap;
    gap: 8px;
    padding: 8px 12px;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 6px;
    background: #fff;
}

.file-entry.file-error {
    border-color: #dc3545;
    background-color: #fff5f5;
}

.file-info {
    flex: 1 1 auto;
}

.error-message {
    color: #dc3545;
    font-size: 0.875rem;
    font-weight: 600;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 2px 10px;
    cursor: pointer;
    font-size: 0.85rem;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

